import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import hospitalService from '../../services/hospitalService';
import HospitalCard from '../../components/hospitals/HospitalCard';
import HospitalStatusBadge from '../../components/hospitals/HospitalStatusBadge';
import { useAuth } from '../../context/AuthContext';

function HospitalListPage() {
  const { user } = useAuth();
  const navigate = useNavigate();

  const isSuperAdmin    = user?.role === 'SUPER_ADMIN';
  const isHospitalAdmin = user?.role === 'HOSPITAL_ADMIN';

  const [hospitals, setHospitals]         = useState([]);
  const [myHospital, setMyHospital]       = useState(null);
  const [loading, setLoading]             = useState(true);
  const [search, setSearch]               = useState('');
  const [filterType, setFilterType]       = useState('');
  const [activeTab, setActiveTab]         = useState('ALL');   // ALL | PENDING | APPROVED | REJECTED | BLACKLISTED
  const [rejectModal, setRejectModal]     = useState({ open: false, hospital: null });
  const [rejectReason, setRejectReason]   = useState('');
  const [actionLoading, setActionLoading] = useState(false);

  // Blacklist modal state
  const [blacklistModal, setBlacklistModal]   = useState({ open: false, hospital: null });
  const [blacklistReason, setBlacklistReason] = useState('');

  const fetchData = async () => {
    setLoading(true);
    try {
      if (isHospitalAdmin) {
        try {
          const data = await hospitalService.getMyHospital();
          setMyHospital(data.data);
        } catch (err) {
          if (err.response?.status === 404) setMyHospital(null);
        }
      } else if (isSuperAdmin) {
        const data = await hospitalService.listHospitals({ status: '' });
        setHospitals(data.data || []);
      } else {
        const params = {};
        if (search)     params.search        = search;
        if (filterType) params.hospital_type = filterType;
        const data = await hospitalService.listHospitals(params);
        setHospitals(data.data || []);
      }
    } catch {
      toast.error('Failed to load hospital data.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, [search, filterType, user?.role]);

  // ── Filtered hospitals for Super Admin tabs ─────────────────────────
  const filteredHospitals = hospitals.filter(h => {
    const matchesSearch = !search ||
      h.hospital_name?.toLowerCase().includes(search.toLowerCase()) ||
      h.city?.toLowerCase().includes(search.toLowerCase());
    const matchesType = !filterType || h.hospital_type === filterType;

    if (!matchesSearch || !matchesType) return false;

    if (activeTab === 'BLACKLISTED') return h.is_blacklisted;
    if (activeTab === 'ALL')         return true;
    // For status tabs, show non-blacklisted with that status
    return !h.is_blacklisted && h.status === activeTab;
  });

  // Tab counts
  const tabCounts = {
    ALL:         hospitals.length,
    PENDING:     hospitals.filter(h => !h.is_blacklisted && h.status === 'PENDING').length,
    APPROVED:    hospitals.filter(h => !h.is_blacklisted && h.status === 'APPROVED').length,
    REJECTED:    hospitals.filter(h => !h.is_blacklisted && h.status === 'REJECTED').length,
    BLACKLISTED: hospitals.filter(h => h.is_blacklisted).length,
  };

  const handleApprove = async (hospital) => {
    setActionLoading(true);
    try {
      await hospitalService.approveReject(hospital.id, 'approve');
      toast.success(`${hospital.hospital_name} approved!`);
      fetchData();
    } catch {
      toast.error('Action failed.');
    } finally {
      setActionLoading(false);
    }
  };

  const handleBlacklist = async () => {
    if (!blacklistReason.trim()) return toast.error('Please provide a reason for blacklisting.');
    setActionLoading(true);
    try {
      await hospitalService.blacklistHospital(blacklistModal.hospital.id, blacklistReason);
      toast.success(`"${blacklistModal.hospital.hospital_name}" blacklisted. Email sent!`);
      setBlacklistModal({ open: false, hospital: null });
      setBlacklistReason('');
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to blacklist.');
    } finally {
      setActionLoading(false);
    }
  };

  const handleUnblacklist = async (hospital) => {
    if (!window.confirm(`Unblacklist "${hospital.hospital_name}"? This will restore admin and doctor accounts.`)) return;
    setActionLoading(true);
    try {
      await hospitalService.unblacklistHospital(hospital.id);
      toast.success(`"${hospital.hospital_name}" unblacklisted! Accounts restored.`);
      fetchData();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to unblacklist.');
    } finally {
      setActionLoading(false);
    }
  };

  const handleRejectSubmit = async () => {
    if (!rejectReason.trim()) return toast.error('Rejection reason is required.');
    setActionLoading(true);
    try {
      await hospitalService.approveReject(rejectModal.hospital.id, 'reject', rejectReason);
      toast.success(`${rejectModal.hospital.hospital_name} rejected.`);
      setRejectModal({ open: false, hospital: null });
      setRejectReason('');
      fetchData();
    } catch {
      toast.error('Action failed.');
    } finally {
      setActionLoading(false);
    }
  };

  // ── Loading ────────────────────────────────────────────────────────────
  if (loading) {
    return (
      <div className="flex items-center justify-center py-24">
        <svg className="animate-spin w-8 h-8 text-blue-500" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
        </svg>
      </div>
    );
  }

  // ══════════════════════════════════════════════════════════════════════
  // HOSPITAL ADMIN VIEW
  // ══════════════════════════════════════════════════════════════════════
  if (isHospitalAdmin) {
    if (!myHospital) {
      return (
        <div className="max-w-lg mx-auto text-center py-20">
          <div className="w-16 h-16 mx-auto mb-4 bg-blue-50 rounded-full flex items-center justify-center">
            <svg className="w-8 h-8 text-blue-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5}
                d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"/>
            </svg>
          </div>
          <h2 className="text-base font-bold text-gray-900 mb-2">No Hospital Registered Yet</h2>
          <p className="text-xs text-gray-500 mb-6">Register your hospital to get started.</p>
          <button onClick={() => navigate('/hospital/register')}
            className="px-6 py-2.5 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors">
            + Register Hospital
          </button>
        </div>
      );
    }

    return (
      <div className="max-w-2xl mx-auto space-y-4">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-lg font-bold text-gray-900">My Hospital</h1>
            <p className="text-xs text-gray-500 mt-0.5">Your hospital registration details</p>
          </div>
          <HospitalStatusBadge status={myHospital.status} />
        </div>

        {myHospital.status === 'PENDING' && (
          <div className="bg-yellow-50 border border-yellow-200 rounded-lg px-4 py-3 flex items-center gap-3">
            <svg className="w-5 h-5 text-yellow-500 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/>
            </svg>
            <p className="text-xs text-yellow-800">
              Your hospital is <strong>pending approval</strong> from the Super Admin.
            </p>
          </div>
        )}
        {myHospital.status === 'APPROVED' && (
          <div className="bg-green-50 border border-green-200 rounded-lg px-4 py-3 flex items-center gap-3">
            <svg className="w-5 h-5 text-green-500 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z"/>
            </svg>
            <p className="text-xs text-green-800">Your hospital is <strong>approved</strong> and live!</p>
          </div>
        )}
        {myHospital.status === 'REJECTED' && (
          <div className="bg-red-50 border border-red-200 rounded-lg px-4 py-3">
            <p className="text-xs font-semibold text-red-800 mb-1">Hospital Rejected</p>
            <p className="text-xs text-red-700">{myHospital.rejection_reason || 'Please contact support.'}</p>
          </div>
        )}

        <div className="bg-white rounded-xl border border-gray-100 shadow-sm overflow-hidden">
          <div className="bg-gradient-to-r from-blue-700 to-blue-900 px-5 py-4 text-white">
            <h2 className="font-bold text-base">{myHospital.hospital_name}</h2>
            <p className="text-blue-200 text-xs mt-0.5">{myHospital.hospital_type?.replace('_', '-')}</p>
          </div>
          <div className="p-5 grid grid-cols-1 sm:grid-cols-2 gap-4 text-xs">
            <div className="space-y-2">
              <p className="font-semibold text-gray-700 uppercase tracking-wide text-xs">Contact</p>
              <div className="text-gray-600 space-y-1.5">
                <p><span className="text-gray-400 w-16 inline-block">Email:</span>{myHospital.email}</p>
                <p><span className="text-gray-400 w-16 inline-block">Phone:</span>{myHospital.phone_number}</p>
              </div>
            </div>
            <div className="space-y-2">
              <p className="font-semibold text-gray-700 uppercase tracking-wide text-xs">Address</p>
              <div className="text-gray-600 space-y-1.5">
                <p>{myHospital.address}</p>
                <p>{myHospital.city}, {myHospital.state} — {myHospital.pincode}</p>
              </div>
            </div>
          </div>
          <div className="px-5 py-3 border-t border-gray-100 flex justify-end">
            <button onClick={() => navigate(`/hospitals/${myHospital.id}`)}
              className="px-4 py-1.5 text-xs font-medium text-blue-600 border border-blue-200 rounded-lg hover:bg-blue-50 transition-colors">
              View Full Details
            </button>
          </div>
        </div>
      </div>
    );
  }

  // ══════════════════════════════════════════════════════════════════════
  // SUPER ADMIN VIEW — tabs with blacklist management
  // ══════════════════════════════════════════════════════════════════════
  if (isSuperAdmin) {
    const TABS = [
      { key: 'ALL',         label: 'All',         color: 'gray'   },
      { key: 'PENDING',     label: 'Pending',      color: 'yellow' },
      { key: 'APPROVED',    label: 'Approved',     color: 'green'  },
      { key: 'REJECTED',    label: 'Rejected',     color: 'red'    },
      { key: 'BLACKLISTED', label: 'Blacklisted',  color: 'black'  },
    ];

    const tabColorMap = {
      gray:   { active: 'bg-gray-800 text-white',   badge: 'bg-gray-200 text-gray-800'   },
      yellow: { active: 'bg-yellow-500 text-white',  badge: 'bg-yellow-100 text-yellow-800' },
      green:  { active: 'bg-green-600 text-white',   badge: 'bg-green-100 text-green-800'  },
      red:    { active: 'bg-red-600 text-white',     badge: 'bg-red-100 text-red-800'      },
      black:  { active: 'bg-gray-900 text-white',    badge: 'bg-gray-900 text-white'       },
    };

    return (
      <div>
        {/* Header */}
        <div className="mb-5 flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
          <div>
            <h1 className="text-lg font-bold text-gray-900">Hospital Management</h1>
            <p className="text-xs text-gray-500 mt-0.5">
              Manage all hospitals — approve, reject, blacklist
            </p>
          </div>
          {/* Search + Filter */}
          <div className="flex gap-2">
            <input
              value={search}
              onChange={e => setSearch(e.target.value)}
              placeholder="Search name, city..."
              className="px-3 py-1.5 text-xs border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400 w-44"
            />
            <select
              value={filterType}
              onChange={e => setFilterType(e.target.value)}
              className="px-2 py-1.5 text-xs border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-400"
            >
              <option value="">All Types</option>
              <option value="GENERAL">General</option>
              <option value="MULTI_SPECIALTY">Multi-Speciality</option>
              <option value="CLINIC">Clinic</option>
              <option value="DIAGNOSTIC">Diagnostic</option>
            </select>
          </div>
        </div>

        {/* Tabs */}
        <div className="flex flex-wrap gap-2 mb-5">
          {TABS.map(tab => {
            const isActive = activeTab === tab.key;
            const colors   = tabColorMap[tab.color];
            const count    = tabCounts[tab.key];
            return (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key)}
                className={`flex items-center gap-2 px-3 py-1.5 rounded-lg text-xs font-medium transition-all
                  ${isActive
                    ? colors.active + ' shadow-sm'
                    : 'bg-white border border-gray-200 text-gray-600 hover:border-gray-400'
                  }`}
              >
                {tab.key === 'BLACKLISTED' && '🚫 '}
                {tab.label}
                <span className={`inline-flex items-center justify-center w-5 h-5 rounded-full text-xs font-bold
                  ${isActive ? 'bg-white/20 text-white' : colors.badge}`}>
                  {count}
                </span>
              </button>
            );
          })}
        </div>

        {/* Blacklisted banner */}
        {activeTab === 'BLACKLISTED' && tabCounts.BLACKLISTED > 0 && (
          <div className="bg-gray-900 text-white rounded-lg px-4 py-3 mb-4 flex items-center gap-3">
            <span className="text-lg">🚫</span>
            <div>
              <p className="text-xs font-semibold">Blacklisted Hospitals</p>
              <p className="text-xs text-gray-400 mt-0.5">
                These hospitals are suspended. All admin and doctor accounts are deactivated.
                Click "Unblacklist" to restore access.
              </p>
            </div>
          </div>
        )}

        {/* Hospital cards */}
        {filteredHospitals.length === 0 ? (
          <div className="text-center py-20">
            <div className="w-14 h-14 mx-auto mb-4 bg-gray-50 rounded-full flex items-center justify-center">
              <svg className="w-7 h-7 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5}
                  d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4"/>
              </svg>
            </div>
            <p className="text-sm font-medium text-gray-500">
              {activeTab === 'BLACKLISTED' ? 'No blacklisted hospitals' :
               activeTab === 'PENDING'     ? 'No pending approvals' :
               'No hospitals found'}
            </p>
            {activeTab === 'PENDING' && (
              <p className="text-xs text-gray-400 mt-1">All hospitals have been reviewed. ✓</p>
            )}
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {filteredHospitals.map(hospital => (
              <div key={hospital.id} className={`relative ${hospital.is_blacklisted ? 'ring-2 ring-gray-800 rounded-xl' : ''}`}>
                {/* Blacklisted overlay badge */}
                {hospital.is_blacklisted && (
                  <div className="absolute top-2 right-2 z-10 bg-gray-900 text-white text-xs px-2 py-0.5 rounded-full font-medium">
                    🚫 Blacklisted
                  </div>
                )}
                <HospitalCard
                  hospital={hospital}
                  showStatus={true}
                  actions={
                    <div className="flex flex-wrap gap-1.5">
                      {/* Approve — only for PENDING non-blacklisted */}
                      {!hospital.is_blacklisted && hospital.status === 'PENDING' && (
                        <button
                          onClick={() => handleApprove(hospital)}
                          disabled={actionLoading}
                          className="px-2.5 py-1 text-xs font-medium text-white bg-green-600 rounded-md hover:bg-green-700 transition-colors disabled:opacity-50"
                        >
                          ✓ Approve
                        </button>
                      )}
                      {/* Reject — only for PENDING non-blacklisted */}
                      {!hospital.is_blacklisted && hospital.status === 'PENDING' && (
                        <button
                          onClick={() => setRejectModal({ open: true, hospital })}
                          disabled={actionLoading}
                          className="px-2.5 py-1 text-xs font-medium text-white bg-red-600 rounded-md hover:bg-red-700 transition-colors disabled:opacity-50"
                        >
                          ✗ Reject
                        </button>
                      )}
                      {/* Blacklist / Unblacklist */}
                      {hospital.is_blacklisted ? (
                        <button
                          onClick={() => handleUnblacklist(hospital)}
                          disabled={actionLoading}
                          className="px-2.5 py-1 text-xs font-medium text-green-700 border border-green-400 rounded-md hover:bg-green-50 transition-colors disabled:opacity-50"
                        >
                          ✓ Unblacklist
                        </button>
                      ) : (
                        <button
                          onClick={() => setBlacklistModal({ open: true, hospital })}
                          disabled={actionLoading}
                          className="px-2.5 py-1 text-xs font-medium text-white bg-gray-800 rounded-md hover:bg-black transition-colors disabled:opacity-50"
                        >
                          🚫 Blacklist
                        </button>
                      )}
                    </div>
                  }
                />

                {/* Blacklist reason strip */}
                {hospital.is_blacklisted && hospital.blacklist_reason && (
                  <div className="bg-gray-900 text-gray-300 text-xs px-4 py-2 rounded-b-xl -mt-1">
                    <span className="text-gray-500">Reason: </span>{hospital.blacklist_reason}
                  </div>
                )}
              </div>
            ))}
          </div>
        )}

        {/* ── Blacklist Modal ─────────────────────────────────────────── */}
        {blacklistModal.open && (
          <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
              <div className="flex items-center gap-3 mb-3">
                <div className="w-10 h-10 bg-gray-900 rounded-xl flex items-center justify-center text-xl flex-shrink-0">
                  🚫
                </div>
                <div>
                  <h3 className="text-sm font-bold text-gray-900">Blacklist Hospital</h3>
                  <p className="text-xs text-gray-500">{blacklistModal.hospital?.hospital_name}</p>
                </div>
              </div>
              <div className="bg-red-50 border border-red-200 rounded-lg px-3 py-2.5 mb-4">
                <p className="text-xs text-red-700">
                  ⚠️ This will <strong>immediately deactivate</strong> the hospital admin account and
                  all associated doctors. A warning email will be sent.
                </p>
              </div>
              <label className="block text-xs font-semibold text-gray-700 mb-1.5">
                Reason for Blacklisting <span className="text-red-500">*</span>
              </label>
              <textarea
                value={blacklistReason}
                onChange={e => setBlacklistReason(e.target.value)}
                rows={3}
                placeholder="e.g. Fraudulent billing practices reported by multiple patients..."
                className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-gray-800"
              />
              <div className="flex justify-end gap-3 mt-4">
                <button
                  onClick={() => { setBlacklistModal({ open: false, hospital: null }); setBlacklistReason(''); }}
                  className="px-4 py-2 text-xs font-medium text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200"
                >
                  Cancel
                </button>
                <button
                  onClick={handleBlacklist}
                  disabled={actionLoading || !blacklistReason.trim()}
                  className="px-4 py-2 text-xs font-medium text-white bg-gray-900 rounded-lg hover:bg-black disabled:opacity-50 flex items-center gap-1.5"
                >
                  {actionLoading ? (
                    <><svg className="animate-spin w-3.5 h-3.5" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"/>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"/>
                    </svg> Blacklisting...</>
                  ) : '🚫 Confirm Blacklist'}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* ── Reject Modal ────────────────────────────────────────────── */}
        {rejectModal.open && (
          <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md p-6">
              <h3 className="text-sm font-bold text-gray-900 mb-1">Reject Hospital</h3>
              <p className="text-xs text-gray-500 mb-4">
                Rejecting: <strong>{rejectModal.hospital?.hospital_name}</strong>
              </p>
              <label className="block text-xs font-medium text-gray-700 mb-1">Reason *</label>
              <textarea
                value={rejectReason}
                onChange={e => setRejectReason(e.target.value)}
                rows={4}
                className="w-full px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-red-400"
                placeholder="Explain why this hospital is being rejected..."
              />
              <div className="flex justify-end gap-3 mt-4">
                <button
                  onClick={() => { setRejectModal({ open: false, hospital: null }); setRejectReason(''); }}
                  className="px-4 py-2 text-xs font-medium text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200"
                >
                  Cancel
                </button>
                <button
                  onClick={handleRejectSubmit}
                  disabled={actionLoading}
                  className="px-4 py-2 text-xs font-medium text-white bg-red-600 rounded-lg hover:bg-red-700 disabled:opacity-50"
                >
                  {actionLoading ? 'Rejecting...' : 'Confirm Reject'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    );
  }

  // ══════════════════════════════════════════════════════════════════════
  // PATIENT / DOCTOR VIEW
  // ══════════════════════════════════════════════════════════════════════
  return (
    <div>
      <div className="flex items-center justify-between mb-5">
        <div>
          <h1 className="text-lg font-bold text-gray-900">Hospitals</h1>
          <p className="text-xs text-gray-500 mt-0.5">Browse approved hospitals on the platform</p>
        </div>
      </div>
      <div className="flex gap-3 mb-5">
        <input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search by name, city..."
          className="flex-1 px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
        />
        <select
          value={filterType}
          onChange={e => setFilterType(e.target.value)}
          className="px-3 py-2 text-sm border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          <option value="">All Types</option>
          <option value="GENERAL">General</option>
          <option value="MULTI_SPECIALTY">Multi-Speciality</option>
          <option value="CLINIC">Clinic</option>
          <option value="DIAGNOSTIC">Diagnostic</option>
        </select>
      </div>
      {hospitals.length === 0 ? (
        <div className="text-center py-20">
          <p className="text-sm font-medium text-gray-600">No hospitals found</p>
          <p className="text-xs text-gray-400 mt-1">Try adjusting your search.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
          {hospitals.map(hospital => (
            <HospitalCard key={hospital.id} hospital={hospital} />
          ))}
        </div>
      )}
    </div>
  );
}
